 1→import { Loader2 } from "lucide-react";
 2→import { useEffect, useState } from "react";
 3→import { useAppContext } from "../../app";
 4→import type { Trajectory } from "../../types";
 5→import { SessionView } from "./session-view";
 6→
 7→interface SharedSessionViewProps {
 8→  shareToken: string;
 9→}
10→
11→export function SharedSessionView({ shareToken }: SharedSessionViewProps) {
12→  const { fetchWithToken } = useAppContext();
13→  const [trajectories, setTrajectories] = useState<Trajectory[] | null>(null);
14→  const [loading, setLoading] = useState(true);
15→  const [error, setError] = useState("");
16→
17→  useEffect(() => {
18→    setLoading(true);
19→    setError("");
20→    fetchWithToken(`/api/shares/${shareToken}`)
21→      .then((res) => {
22→        if (!res.ok) throw new Error(res.status === 404 ? "Share not found or has been revoked" : `Failed to load: ${res.status}`);
23→        return res.json();
24→      })
25→      .then((data: Trajectory[]) => {
26→        if (!data.length) throw new Error("Share contains no session data");
27→        setTrajectories(data);
28→      })
29→      .catch((err: Error) => setError(err.message))
30→      .finally(() => setLoading(false));
31→  }, [shareToken, fetchWithToken]);
32→
33→  if (loading) {
34→    return (
35→      <div className="flex items-center justify-center h-full">
36→        <div className="text-center">
37→          <Loader2 className="w-8 h-8 text-cyan-500 animate-spin mx-auto mb-2" />
38→          <p className="text-sm text-zinc-400">Loading shared session...</p>
39→        </div>
40→      </div>
41→    );
42→  }
43→
44→  if (error) {
45→    return (
46→      <div className="flex items-center justify-center h-full p-4">
47→        <div className="text-center bg-rose-900/20 border border-rose-800 rounded-lg p-6 max-w-md">
48→          <p className="text-sm font-semibold text-rose-300 mb-2">Failed to load shared session</p>
49→          <p className="text-xs text-rose-400 font-mono break-all">{error}</p>
50→        </div>
51→      </div>
52→    );
53→  }
54→
55→  if (!trajectories?.length) return null;
56→
57→  // Render using the existing SessionView with shared data passed directly
58→  const sessionId = trajectories[0].session_id;
59→  return <SessionView sessionId={sessionId} sharedTrajectories={trajectories} shareToken={shareToken} />;
60→}
