  1→import {
  2→  Loader2,
  3→  Download,
  4→  Share2,
  5→  Check,
  6→  BarChart3,
  7→  Bot,
  8→  Clock,
  9→  MessageSquare,
 10→  Wrench,
 11→  FolderOpen,
 12→  Cpu,
 13→  Calendar,
 14→  Hash,
 15→  Layers,
 16→  Zap,
 17→  GitBranch,
 18→  List,
 19→  ChevronUp,
 20→  ChevronDown,
 21→} from "lucide-react";
 22→import { useCallback, useEffect, useMemo, useRef, useState } from "react";
 23→import { useAppContext } from "../../app";
 24→import type { Step, Trajectory, FlowData } from "../../types";
 25→import { StepBlock } from "./message-block";
 26→import { SubAgentBlock } from "./sub-agent-block";
 27→import { StepTimeline } from "./step-timeline";
 28→import { PromptNavPanel } from "./prompt-nav-panel";
 29→import { FlowDiagram } from "./flow-diagram";
 30→import { computeFlow, type FlowPhaseGroup } from "./flow-layout";
 31→import { formatTokens, formatDuration, formatCost, extractUserText, baseProjectName } from "../../utils";
 32→import { TOGGLE_ACTIVE, TOGGLE_INACTIVE, METRIC_LABEL } from "../../styles";
 33→
 34→interface SessionViewProps {
 35→  sessionId: string;
 36→  sharedTrajectories?: Trajectory[];
 37→  shareToken?: string;
 38→}
 39→
 40→export function SessionView({ sessionId, sharedTrajectories, shareToken }: SessionViewProps) {
 41→  const { fetchWithToken } = useAppContext();
 42→  const [trajectories, setTrajectories] = useState<Trajectory[]>([]);
 43→  const [loading, setLoading] = useState(true);
 44→  const [error, setError] = useState("");
 45→  const [activeStepId, setActiveStepId] = useState<string | null>(null);
 46→  const [promptNavWidth, setPromptNavWidth] = useState(224);
 47→  const [sessionCost, setSessionCost] = useState<number | null>(null);
 48→  const [shareStatus, setShareStatus] = useState<"idle" | "sharing" | "copied">("idle");
 49→  const [viewMode, setViewMode] = useState<"timeline" | "flow">("timeline");
 50→  const [flowData, setFlowData] = useState<FlowData | null>(null);
 51→  const [flowLoading, setFlowLoading] = useState(false);
 52→  const [headerExpanded, setHeaderExpanded] = useState(true);
 53→  const stepsRef = useRef<HTMLDivElement>(null);
 54→  const isNavigatingRef = useRef(false);
 55→  const isSharedView = !!sharedTrajectories;
 56→
 57→  const MIN_PROMPT_NAV_WIDTH = 160;
 58→  const MAX_PROMPT_NAV_WIDTH = 400;
 59→
 60→  const handlePromptNavResize = useCallback((delta: number) => {
 61→    setPromptNavWidth((w) =>
 62→      Math.min(MAX_PROMPT_NAV_WIDTH, Math.max(MIN_PROMPT_NAV_WIDTH, w + delta))
 63→    );
 64→  }, []);
 65→
 66→  useEffect(() => {
 67→    setActiveStepId(null);
 68→    setSessionCost(null);
 69→    setFlowData(null);
 70→    setViewMode("timeline");
 71→
 72→    // When rendering shared data, skip the API fetch
 73→    if (sharedTrajectories) {
 74→      setTrajectories(sharedTrajectories);
 75→      setLoading(false);
 76→      return;
 77→    }
 78→
 79→    setLoading(true);
 80→    setError("");
 81→    setTrajectories([]);
 82→
 83→    fetchWithToken(`/api/sessions/${sessionId}`)
 84→      .then((res) => {
 85→        if (!res.ok) throw new Error(`Failed to load session: ${res.status}`);
 86→        return res.json();
 87→      })
 88→      .then((data: Trajectory[]) => {
 89→        setTrajectories(data);
 90→      })
 91→      .catch((err: Error) => setError(err.message))
 92→      .finally(() => setLoading(false));
 93→  }, [sessionId, fetchWithToken, sharedTrajectories]);
 94→
 95→  // Fetch session analytics for cost estimation (non-blocking, skip for shared views)
 96→  useEffect(() => {
 97→    if (!sessionId || loading || isSharedView) return;
 98→    fetchWithToken(`/api/analysis/sessions/${sessionId}/stats`)
 99→      .then((res) => (res.ok ? res.json() : null))
100→      .then((data) => {
101→        if (data?.cost_usd != null) setSessionCost(data.cost_usd);
102→      })
103→      .catch(() => {});
104→  }, [sessionId, loading, fetchWithToken]);
105→
106→  // Fetch flow data lazily when user toggles to flow view
107→  useEffect(() => {
108→    if (viewMode !== "flow" || flowData || flowLoading || !sessionId) return;
109→    setFlowLoading(true);
110→    const url = isSharedView && shareToken
111→      ? `/api/shares/${shareToken}/flow`
112→      : `/api/sessions/${sessionId}/flow`;
113→    fetchWithToken(url)
114→      .then((res) => (res.ok ? res.json() : null))
115→      .then((data: FlowData | null) => {
116→        if (data) setFlowData(data);
117→      })
118→      .catch(() => {})
119→      .finally(() => setFlowLoading(false));
120→  }, [viewMode, flowData, flowLoading, sessionId, fetchWithToken, isSharedView, shareToken]);
121→
122→  const main = useMemo(
123→    () => trajectories.find((t) => !t.parent_trajectory_ref) ?? trajectories[0] ?? null,
124→    [trajectories]
125→  );
126→
127→  const subAgents = useMemo(
128→    () =>
129→      trajectories
130→        .filter((t) => !!t.parent_trajectory_ref)
131→        .sort((a, b) => {
132→          const ta = a.timestamp ? new Date(a.timestamp).getTime() : 0;
133→          const tb = b.timestamp ? new Date(b.timestamp).getTime() : 0;
134→          return ta - tb;
135→        }),
136→    [trajectories]
137→  );
138→
139→  // Build a map: step_id -> sub-agent trajectories spawned from that step.
140→  // Phase 1 links via observation.subagent_trajectory_ref (explicit linkage).
141→  // Phase 2 places unlinked sub-agents (e.g. compaction) at the
142→  // chronologically correct position using timestamp heuristics.
143→  const subAgentsByStep = useMemo(() => {
144→    const map = new Map<string, Trajectory[]>();
145→    const orphans: Trajectory[] = [];
146→    const unlinked: Trajectory[] = [];
147→
148→    for (const sub of subAgents) {
149→      let placed = false;
150→      if (main?.steps) {
151→        for (const step of main.steps) {
152→          if (!step.observation) continue;
153→          for (const result of step.observation.results) {
154→            if (!result.subagent_trajectory_ref) continue;
155→            for (const ref of result.subagent_trajectory_ref) {
156→              if (ref.session_id === sub.session_id) {
157→                const existing = map.get(step.step_id) || [];
158→                existing.push(sub);
159→                map.set(step.step_id, existing);
160→                placed = true;
161→                break;
162→              }
163→            }
164→            if (placed) break;
165→          }
166→          if (placed) break;
167→        }
168→      }
169→      if (!placed) unlinked.push(sub);
170→    }
171→
172→    // Place unlinked sub-agents at the last main step whose timestamp
173→    // is <= the sub-agent's start timestamp. Falls back to orphans
174→    // only when no timestamp is available.
175→    for (const sub of unlinked) {
176→      const subTs = sub.timestamp ? new Date(sub.timestamp).getTime() : NaN;
177→      if (!isNaN(subTs) && main?.steps) {
178→        let bestStepId: string | null = null;
179→        for (const step of main.steps) {
180→          if (!step.timestamp) continue;
181→          const stepTs = new Date(step.timestamp).getTime();
182→          if (stepTs <= subTs) bestStepId = step.step_id;
183→          else break;
184→        }
185→        if (bestStepId) {
186→          const existing = map.get(bestStepId) || [];
187→          existing.push(sub);
188→          map.set(bestStepId, existing);
189→          continue;
190→        }
191→      }
192→      orphans.push(sub);
193→    }
194→
195→    return { map, orphans };
196→  }, [main, subAgents]);
197→
198→  const steps = (main?.steps || []) as Step[];
199→
200→  const userStepIds = useMemo(() => {
201→    return steps
202→      .filter((s) => s.source === "user" && extractUserText(s))
203→      .map((s) => s.step_id);
204→  }, [steps]);
205→
206→  // Compute flow phases for the nav panel when in flow mode
207→  const flowPhases: FlowPhaseGroup[] | undefined = useMemo(() => {
208→    if (!flowData || viewMode !== "flow") return undefined;
209→    const result = computeFlow(steps, flowData.tool_graph, flowData.phase_segments);
210→    return result.phases;
211→  }, [flowData, viewMode, steps]);
212→
213→  const [activePhaseIdx, setActivePhaseIdx] = useState<number | null>(null);
214→
215→  const SCROLL_SUPPRESS_MS = 800;
216→
217→  const handlePhaseNavigate = useCallback((phaseIdx: number) => {
218→    const el = document.getElementById(`flow-phase-${phaseIdx}`);
219→    if (!el) return;
220→    setActivePhaseIdx(phaseIdx);
221→    el.scrollIntoView({ behavior: "smooth", block: "start" });
222→  }, []);
223→
224→  // IntersectionObserver to track which user prompt is currently visible
225→  useEffect(() => {
226→    if (!stepsRef.current || userStepIds.length < 2) return;
227→
228→    const observer = new IntersectionObserver(
229→      (entries) => {
230→        if (isNavigatingRef.current) return;
231→        let topEntry: IntersectionObserverEntry | null = null;
232→        for (const entry of entries) {
233→          if (!entry.isIntersecting) continue;
234→          if (!topEntry || entry.boundingClientRect.top < topEntry.boundingClientRect.top) {
235→            topEntry = entry;
236→          }
237→        }
238→        if (topEntry) {
239→          setActiveStepId(topEntry.target.id.replace("step-", ""));
240→        }
241→      },
242→      {
243→        root: stepsRef.current,
244→        rootMargin: "-10% 0px -80% 0px",
245→        threshold: 0,
246→      }
247→    );
248→
249→    for (const stepId of userStepIds) {
250→      const el = document.getElementById(`step-${stepId}`);
251→      if (el) observer.observe(el);
252→    }
253→
254→    return () => observer.disconnect();
255→  }, [userStepIds]);
256→
257→  const handlePromptNavigate = useCallback((stepId: string) => {
258→    const el = document.getElementById(`step-${stepId}`);
259→    if (!el) return;
260→    isNavigatingRef.current = true;
261→    setActiveStepId(stepId);
262→    el.scrollIntoView({ behavior: "smooth", block: "start" });
263→    setTimeout(() => {
264→      isNavigatingRef.current = false;
265→    }, SCROLL_SUPPRESS_MS);
266→  }, []);
267→
268→  if (loading) {
269→    return (
270→      <div className="flex items-center justify-center h-full">
271→        <div className="flex flex-col items-center gap-5">
272→          <div className="relative flex items-center justify-center">
273→            {/* Ambient glow */}
274→            <div className="absolute w-24 h-24 bg-cyan-500/10 rounded-full blur-2xl animate-pulse" />
275→            {/* Track ring */}
276→            <div className="w-16 h-16 rounded-full border-[3px] border-zinc-800" />
277→            {/* Spinning arc */}
278→            <div className="absolute w-16 h-16 rounded-full border-[3px] border-transparent border-t-cyan-400 animate-spin" />
279→          </div>
280→          <div className="text-center space-y-1">
281→            <p className="text-base font-medium text-zinc-200">Loading session</p>
282→            <p className="text-xs text-zinc-500">Parsing trajectory data…</p>
283→          </div>
284→        </div>
285→      </div>
286→    );
287→  }
288→
289→  if (error) {
290→    return (
291→      <div className="flex items-center justify-center h-full p-4">
292→        <div className="text-center bg-rose-900/20 border border-rose-800 rounded-lg p-6 max-w-md">
293→          <p className="text-sm font-semibold text-rose-300 mb-2">Failed to load session</p>
294→          <p className="text-xs text-rose-400 mb-4 font-mono break-all">{error}</p>
295→          <button
296→            onClick={() => window.location.reload()}
297→            className="px-3 py-1 bg-rose-700/50 hover:bg-rose-700 rounded text-xs text-rose-200 transition"
298→          >
299→            Retry
300→          </button>
301→        </div>
302→      </div>
303→    );
304→  }
305→
306→  const handleShare = async () => {
307→    setShareStatus("sharing");
308→    try {
309→      const res = await fetchWithToken("/api/shares", {
310→        method: "POST",
311→        headers: { "Content-Type": "application/json" },
312→        body: JSON.stringify({ session_id: sessionId }),
313→      });
314→      if (!res.ok) throw new Error(`Failed to create share: ${res.status}`);
315→      const data = await res.json();
316→      await navigator.clipboard.writeText(data.url);
317→      setShareStatus("copied");
318→      setTimeout(() => setShareStatus("idle"), 2000);
319→    } catch (err) {
320→      console.error("Share failed:", err);
321→      setShareStatus("idle");
322→    }
323→  };
324→
325→  if (!main) return null;
326→
327→  const metrics = main.final_metrics;
328→  const promptCount = steps.filter(
329→    (s) => s.source === "user" && !s.extra?.is_skill_output && extractUserText(s)
330→  ).length;
331→  const skillCount = steps.filter(
332→    (s) => s.source === "user" && s.extra?.is_skill_output
333→  ).length;
334→  const totalTokens =
335→    (metrics?.total_prompt_tokens || 0) +
336→    (metrics?.total_completion_tokens || 0);
337→
338→  const isVisibleStep = (s: Step): boolean => {
339→    if (s.source === "user") {
340→      if (typeof s.message === "string") return !!s.message.trim();
341→      return s.message.length > 0;
342→    }
343→    return s.source === "agent" || s.source === "system";
344→  };
345→
346→  return (
347→    <div className="h-full flex flex-col overflow-hidden">
348→      {/* Session Header */}
349→      <div className="shrink-0 bg-gradient-to-b from-zinc-900 to-zinc-900/80 border-b border-zinc-800 px-4 py-2">
350→        <div className="max-w-7xl mx-auto">
351→          {/* Row 1: Session ID + Title + Actions */}
352→          <div className="flex items-center justify-between mb-1 gap-3">
353→            <div className="flex items-center gap-2.5 min-w-0 flex-1">
354→              <MetaPill
355→                icon={<Hash className="w-3 h-3" />}
356→                label={main.session_id.slice(0, 8)}
357→                color="text-zinc-300"
358→                tooltip={`Session ID: ${main.session_id}`}
359→              />
360→              <h2
361→                className="text-lg font-semibold text-zinc-100 truncate"
362→                title={main.first_message || "Session"}
363→              >
364→                {main.first_message || "Session"}
365→              </h2>
366→            </div>
367→            <div className="flex items-center gap-1 shrink-0 ml-3">
368→              {/* View mode toggle */}
369→              <div className="flex rounded-md border border-zinc-700 mr-2">
370→                <button
371→                  onClick={() => setViewMode("timeline")}
372→                  className={`flex items-center gap-1 px-2.5 py-1.5 text-xs rounded-l-md transition ${
373→                    viewMode === "timeline" ? TOGGLE_ACTIVE : TOGGLE_INACTIVE
374→                  }`}
375→                >
376→                  <List className="w-3 h-3" />
377→                  Timeline
378→                </button>
379→                <button
380→                  onClick={() => setViewMode("flow")}
381→                  className={`flex items-center gap-1 px-2.5 py-1.5 text-xs rounded-r-md transition ${
382→                    viewMode === "flow" ? TOGGLE_ACTIVE : TOGGLE_INACTIVE
383→                  }`}
384→                >
385→                  <GitBranch className="w-3 h-3" />
386→                  Flow
387→                </button>
388→              </div>
389→              {!isSharedView && (
390→                <button
391→                  onClick={handleShare}
392→                  disabled={shareStatus === "sharing"}
393→                  className="p-2 text-zinc-400 hover:text-zinc-200 hover:bg-zinc-800 rounded transition text-xs disabled:opacity-50"
394→                  title={shareStatus === "copied" ? "Link copied!" : "Share session"}
395→                >
396→                  {shareStatus === "copied" ? (
397→                    <Check className="w-4 h-4 text-emerald-400" />
398→                  ) : shareStatus === "sharing" ? (
399→                    <Loader2 className="w-4 h-4 animate-spin" />
400→                  ) : (
401→                    <Share2 className="w-4 h-4" />
402→                  )}
403→                </button>
404→              )}
405→              <button
406→                onClick={() => {
407→                  const link = document.createElement("a");
408→                  link.href = `/api/sessions/${sessionId}/export`;
409→                  link.download = `vibelens-${sessionId.slice(0, 8)}.json`;
410→                  document.body.appendChild(link);
411→                  link.click();
412→                  document.body.removeChild(link);
413→                }}
414→                className="p-2 text-zinc-400 hover:text-zinc-200 hover:bg-zinc-800 rounded transition text-xs"
415→                title="Download session"
416→              >
417→                <Download className="w-4 h-4" />
418→              </button>
419→              <button
420→                onClick={() => setHeaderExpanded((v) => !v)}
421→                className="p-2 text-zinc-400 hover:text-zinc-200 hover:bg-zinc-800 rounded transition text-xs"
422→                title={headerExpanded ? "Collapse header" : "Expand header"}
423→              >
424→                {headerExpanded ? <ChevronUp className="w-4 h-4" /> : <ChevronDown className="w-4 h-4" />}
425→              </button>
426→            </div>
427→          </div>
428→
429→          {headerExpanded && <>
430→          {/* Row 2: Meta Pills (full width) */}
431→          <div className="flex flex-wrap items-center gap-1.5 mb-3">
432→            {main.agent.model_name && (
433→              <MetaPill
434→                icon={<Cpu className="w-3 h-3" />}
435→                label={`${main.agent.name}@${main.agent.model_name}`}
436→                color="text-amber-300"
437→                tooltip="Agent model used for this session"
438→              />
439→            )}
440→            {main.timestamp && (
441→              <MetaPill
442→                icon={<Calendar className="w-3 h-3" />}
443→                label={formatCreatedTime(main.timestamp)}
444→                color="text-zinc-200"
445→                tooltip="Session start time"
446→              />
447→            )}
448→            {metrics && (
449→              <MetaPill
450→                icon={<Clock className="w-3 h-3" />}
451→                label={formatDuration(metrics.duration)}
452→                color="text-cyan-400"
453→                tooltip="Total wall-clock duration of this session"
454→              />
455→            )}
456→            <MetaPill
457→              icon={<MessageSquare className="w-3 h-3" />}
458→              label={`${promptCount} prompt${promptCount !== 1 ? "s" : ""}`}
459→              color="text-blue-400"
460→              tooltip="User prompts — messages typed by the human operator"
461→            />
462→            {skillCount > 0 && (
463→              <MetaPill
464→                icon={<Zap className="w-3 h-3" />}
465→                label={`${skillCount} skill${skillCount !== 1 ? "s" : ""}`}
466→                color="text-amber-300"
467→                tooltip="Skill invocations — reusable prompts auto-injected by the agent"
468→              />
469→            )}
470→            {metrics && (
471→              <>
472→                <MetaPill
473→                  icon={<Wrench className="w-3 h-3" />}
474→                  label={`${metrics.tool_call_count} tools`}
475→                  color="text-amber-400"
476→                  tooltip="Total tool calls made by the agent (Bash, Read, Edit, etc.)"
477→                />
478→                {metrics.total_steps && (
479→                  <MetaPill
480→                    icon={<Layers className="w-3 h-3" />}
481→                    label={`${metrics.total_steps} steps`}
482→                    color="text-zinc-200"
483→                    tooltip="Total conversation steps including user, agent, and system turns"
484→                  />
485→                )}
486→              </>
487→            )}
488→            {subAgents.length > 0 && (
489→              <MetaPill
490→                icon={<Bot className="w-3 h-3" />}
491→                label={`${subAgents.length} sub-agent${subAgents.length !== 1 ? "s" : ""}`}
492→                color="text-violet-400"
493→                tooltip="Sub-agent tasks spawned during this session"
494→              />
495→            )}
496→            {main.project_path && (
497→              <MetaPill
498→                icon={<FolderOpen className="w-3 h-3" />}
499→                label={baseProjectName(main.project_path)}
500→                color="text-zinc-200"
501→                tooltip={main.project_path}
502→              />
503→            )}
504→          </div>
505→
506→          {/* Row 3: Token Stats */}
507→          {metrics && (metrics.total_prompt_tokens != null || metrics.total_completion_tokens != null) && (
508→            <div className={`grid ${sessionCost != null ? "grid-cols-6" : "grid-cols-5"} gap-2 text-xs`}>
509→              <TokenStat label="Input" value={metrics.total_prompt_tokens || 0} color="text-cyan-300" tooltip="Prompt tokens sent to the model" />
510→              <TokenStat label="Output" value={metrics.total_completion_tokens || 0} color="text-cyan-300" tooltip="Completion tokens generated by the model" />
511→              <TokenStat label="Cache Read" value={metrics.total_cache_read || 0} color="text-green-300" tooltip="Tokens served from prompt cache (reduced cost)" />
512→              <TokenStat label="Cache Write" value={metrics.total_cache_write || 0} color="text-violet-300" tooltip="Tokens written to prompt cache for future reuse" />
513→              <TokenStat label="Total" value={totalTokens} color="text-amber-300" tooltip="Total tokens (input + output)" />
514→              {sessionCost != null && (
515→                <CostStat value={sessionCost} />
516→              )}
517→            </div>
518→          )}
519→          </>}
520→        </div>
521→      </div>
522→
523→      {/* Two-column body: Steps + Prompt Nav */}
524→      <div className="flex-1 flex min-h-0">
525→        {/* Steps / Flow */}
526→        <div ref={stepsRef} className="flex-1 overflow-y-auto">
