533→                </div>
534→              ) : (
535→                <>
536→                  <StepTimeline
537→                    entries={steps
538→                      .filter((step) => {
539→                        const visible = isVisibleStep(step);
540→                        const spawnedSubs = subAgentsByStep.map.get(step.step_id);
541→                        return visible || !!spawnedSubs;
542→                      })
543→                      .map((step) => {
544→                        const visible = isVisibleStep(step);
545→                        const spawnedSubs = subAgentsByStep.map.get(step.step_id);
546→                        return {
547→                          step,
548→                          content: (
549→                            <div id={`step-${step.step_id}`} style={{ scrollMarginTop: "1rem" }}>
