  1→import {
  2→  Search,
  3→  CheckSquare,
  4→  Square,
  5→  MinusSquare,
  6→  Clock,
  7→  FolderOpen,
  8→  ChevronDown,
  9→  ChevronRight,
 10→  Bot,
 11→  SlidersHorizontal,
 12→  Loader2,
 13→} from "lucide-react";
 14→import { useCallback, useEffect, useMemo, useRef, useState } from "react";
 15→import { useAppContext } from "../app";
 16→import type { Trajectory } from "../types";
 17→import { formatTime, truncate, baseProjectName } from "../utils";
 18→import { SearchOptionsDialog } from "./search-options-dialog";
 19→import { TOGGLE_CONTAINER, TOGGLE_BUTTON_BASE, TOGGLE_ACTIVE, TOGGLE_INACTIVE } from "../styles";
 20→
 21→export type ViewMode = "time" | "project";
 22→
 23→interface SessionListProps {
 24→  sessions: Trajectory[];
 25→  selectedId: string | null;
 26→  onSelect: (id: string) => void;
 27→  checkedIds: Set<string>;
 28→  onCheckedChange: (ids: Set<string>) => void;
 29→  viewMode: ViewMode;
 30→  onViewModeChange: (mode: ViewMode) => void;
 31→  agentFilter: string;
 32→  onAgentFilterChange: (agent: string) => void;
 33→  availableAgents: string[];
 34→}
 35→
 36→export function SessionList({
 37→  sessions,
 38→  selectedId,
 39→  onSelect,
 40→  checkedIds,
 41→  onCheckedChange,
 42→  viewMode,
 43→  onViewModeChange,
 44→  agentFilter,
 45→  onAgentFilterChange,
 46→  availableAgents,
 47→}: SessionListProps) {
 48→  const { fetchWithToken } = useAppContext();
 49→  const [search, setSearch] = useState("");
 50→  const [expandedProjects, setExpandedProjects] = useState<Set<string>>(
 51→    new Set()
 52→  );
 53→  const [searchResults, setSearchResults] = useState<Set<string> | null>(null);
 54→  const [searchLoading, setSearchLoading] = useState(false);
 55→  const [showSearchOptions, setShowSearchOptions] = useState(false);
 56→  const [searchSources, setSearchSources] = useState<Set<string>>(
 57→    () => new Set(["user_prompts"])
 58→  );
 59→  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
 60→
 61→  const SEARCH_DEBOUNCE_MS = 300;
 62→  const DEFAULT_SOURCES = new Set(["user_prompts"]);
 63→  const hasNonDefaultSources =
 64→    searchSources.size !== DEFAULT_SOURCES.size ||
 65→    ![...DEFAULT_SOURCES].every((s) => searchSources.has(s));
 66→
 67→  const runSearch = useCallback(
 68→    (query: string, sources: Set<string>) => {
 69→      if (!query.trim()) {
 70→        setSearchResults(null);
 71→        setSearchLoading(false);
 72→        return;
 73→      }
 74→
 75→      setSearchLoading(true);
 76→      const params = new URLSearchParams({
 77→        q: query.trim(),
 78→        sources: [...sources].join(","),
 79→      });
 80→
 81→      fetchWithToken(`/api/sessions/search?${params}`)
 82→        .then((r) => r.json())
 83→        .then((ids: string[]) => setSearchResults(new Set(ids)))
 84→        .catch((err) => {
 85→          console.error("Search failed:", err);
 86→          setSearchResults(null);
 87→        })
 88→        .finally(() => setSearchLoading(false));
 89→    },
 90→    [fetchWithToken]
 91→  );
 92→
 93→  useEffect(() => {
 94→    if (debounceRef.current) clearTimeout(debounceRef.current);
 95→    debounceRef.current = setTimeout(
 96→      () => runSearch(search, searchSources),
 97→      SEARCH_DEBOUNCE_MS
 98→    );
 99→    return () => {
100→      if (debounceRef.current) clearTimeout(debounceRef.current);
101→    };
102→  }, [search, searchSources, runSearch]);
103→
104→  const filtered = sessions.filter((s) => {
105→    if (agentFilter !== "all" && s.agent?.name !== agentFilter) return false;
106→    if (!search) return true;
107→    if (searchResults !== null) return searchResults.has(s.session_id);
108→    // While search is pending, keep showing all to avoid flash
109→    return true;
110→  });
111→
112→  const filteredIds = new Set(filtered.map((s) => s.session_id));
113→  const checkedInView = [...checkedIds].filter((id) => filteredIds.has(id));
114→  const allChecked =
115→    filtered.length > 0 && checkedInView.length === filtered.length;
116→  const someChecked = checkedInView.length > 0 && !allChecked;
117→
118→  const groupedByProject = useMemo(() => {
119→    const groups = new Map<string, Trajectory[]>();
120→    for (const session of filtered) {
121→      const key = session.project_path || "Unknown";
122→      const list = groups.get(key) || [];
123→      list.push(session);
124→      groups.set(key, list);
125→    }
126→    return groups;
127→  }, [filtered]);
128→
129→  const handleSetViewMode = (mode: ViewMode) => {
130→    if (mode === "project" && viewMode !== "project") {
131→      setExpandedProjects(new Set());
132→    }
133→    onViewModeChange(mode);
134→  };
135→
136→  const toggleProjectExpanded = (projectName: string) => {
137→    const next = new Set(expandedProjects);
138→    if (next.has(projectName)) {
139→      next.delete(projectName);
140→    } else {
141→      next.add(projectName);
142→    }
143→    setExpandedProjects(next);
144→  };
145→
146→  const handleToggleAll = () => {
147→    if (allChecked) {
148→      const next = new Set(checkedIds);
149→      for (const s of filtered) next.delete(s.session_id);
150→      onCheckedChange(next);
151→    } else {
152→      const next = new Set(checkedIds);
153→      for (const s of filtered) next.add(s.session_id);
154→      onCheckedChange(next);
155→    }
156→  };
157→
158→  const handleToggleOne = (sessionId: string) => {
159→    const next = new Set(checkedIds);
160→    if (next.has(sessionId)) {
161→      next.delete(sessionId);
162→    } else {
163→      next.add(sessionId);
164→    }
165→    onCheckedChange(next);
166→  };
167→
168→  return (
169→    <div className="flex flex-col flex-1 min-h-0">
170→      <div className="p-3 space-y-2 border-b border-zinc-800">
171→        {/* View Mode Toggle */}
172→        <div className={TOGGLE_CONTAINER}>
173→          <button
174→            onClick={() => handleSetViewMode("project")}
175→            className={`${TOGGLE_BUTTON_BASE} ${
176→              viewMode === "project" ? TOGGLE_ACTIVE : TOGGLE_INACTIVE
177→            }`}
178→          >
179→            <FolderOpen className="w-3.5 h-3.5" />
180→            By Project
181→          </button>
182→          <button
183→            onClick={() => handleSetViewMode("time")}
184→            className={`${TOGGLE_BUTTON_BASE} ${
185→              viewMode === "time" ? TOGGLE_ACTIVE : TOGGLE_INACTIVE
186→            }`}
187→          >
188→            <Clock className="w-3.5 h-3.5" />
189→            By Time
190→          </button>
191→        </div>
192→
193→        <div className="relative">
194→          {searchLoading ? (
195→            <Loader2 className="absolute left-2 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-cyan-400 animate-spin" />
196→          ) : (
197→            <Search className="absolute left-2 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-zinc-500" />
198→          )}
199→          <input
200→            type="text"
201→            placeholder="Search sessions..."
202→            value={search}
203→            onChange={(e) => setSearch(e.target.value)}
204→            className="w-full bg-zinc-800 text-zinc-200 text-sm rounded pl-7 pr-8 py-1.5 border border-zinc-700 focus:outline-none focus:border-cyan-600 placeholder:text-zinc-500"
205→          />
206→          <button
207→            onClick={() => setShowSearchOptions(true)}
208→            className="absolute right-1.5 top-1/2 -translate-y-1/2 p-0.5 text-zinc-500 hover:text-zinc-300 transition"
209→            title="Search options"
210→          >
211→            <div className="relative">
212→              <SlidersHorizontal className="w-3.5 h-3.5" />
213→              {hasNonDefaultSources && (
214→                <span className="absolute -top-0.5 -right-0.5 w-1.5 h-1.5 bg-cyan-400 rounded-full" />
215→              )}
216→            </div>
217→          </button>
218→        </div>
219→
220→        {showSearchOptions && (
221→          <SearchOptionsDialog
222→            sources={searchSources}
223→            onApply={setSearchSources}
224→            onClose={() => setShowSearchOptions(false)}
225→          />
226→        )}
227→
228→        {/* Agent Filter */}
229→        {availableAgents.length > 0 && (
230→          <div className="relative">
231→            <Bot className="absolute left-2 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-zinc-500" />
232→            <select
233→              value={agentFilter}
234→              onChange={(e) => onAgentFilterChange(e.target.value)}
235→              className="w-full bg-zinc-800 text-zinc-200 text-sm rounded pl-7 pr-2 py-1.5 border border-zinc-700 focus:outline-none focus:border-cyan-600 appearance-none cursor-pointer"
236→            >
237→              <option value="all">All agents</option>
238→              {availableAgents.map((agent) => (
239→                <option key={agent} value={agent}>
240→                  {agent}
241→                </option>
242→              ))}
243→            </select>
244→          </div>
245→        )}
246→
247→        {/* Select All */}
248→        <button
249→          onClick={handleToggleAll}
250→          className="flex items-center gap-1.5 text-xs text-zinc-300 hover:text-zinc-100 transition"
251→        >
252→          {allChecked ? (
253→            <CheckSquare className="w-3.5 h-3.5 text-cyan-400" />
254→          ) : someChecked ? (
255→            <MinusSquare className="w-3.5 h-3.5 text-cyan-400" />
256→          ) : (
257→            <Square className="w-3.5 h-3.5" />
258→          )}
259→          Select all ({filtered.length})
260→        </button>
261→      </div>
262→
263→      <div className="flex-1 overflow-y-auto">
264→        {viewMode === "time" ? (
265→          filtered.map((session) => (
266→            <SessionRow
267→              key={session.session_id}
268→              session={session}
269→              selectedId={selectedId}
270→              checkedIds={checkedIds}
271→              onSelect={onSelect}
272→              onToggle={handleToggleOne}
273→              showProject
274→            />
275→          ))
276→        ) : (
277→          Array.from(groupedByProject.entries()).map(
278→            ([projectName, projectSessions]) => {
279→              const projectIds = projectSessions.map((s) => s.session_id);
280→              const allProjectChecked = projectIds.every((id) =>
281→                checkedIds.has(id)
282→              );
283→              const someProjectChecked =
284→                !allProjectChecked &&
285→                projectIds.some((id) => checkedIds.has(id));
286→              const handleToggleProject = (e: React.MouseEvent) => {
287→                e.stopPropagation();
288→                const next = new Set(checkedIds);
289→                if (allProjectChecked) {
290→                  for (const id of projectIds) next.delete(id);
291→                } else {
292→                  for (const id of projectIds) next.add(id);
293→                }
294→                onCheckedChange(next);
295→              };
296→              return (
297→              <div key={projectName}>
298→                <div className="sticky top-0 z-10 w-full flex items-center gap-1 bg-zinc-900 border-b border-zinc-800 text-sm text-zinc-200">
299→                  <button
300→                    onClick={handleToggleProject}
301→                    className="shrink-0 pl-3 pr-1 py-2 text-zinc-500 hover:text-cyan-400 transition"
302→                    title={allProjectChecked ? "Deselect project" : "Select project"}
303→                  >
304→                    {allProjectChecked ? (
305→                      <CheckSquare className="w-3.5 h-3.5 text-cyan-400" />
306→                    ) : someProjectChecked ? (
307→                      <MinusSquare className="w-3.5 h-3.5 text-cyan-400" />
308→                    ) : (
309→                      <Square className="w-3.5 h-3.5" />
310→                    )}
311→                  </button>
312→                  <button
313→                    onClick={() => toggleProjectExpanded(projectName)}
314→                    className="flex-1 flex items-center gap-2 pr-3 py-2 hover:text-zinc-100 transition min-w-0"
315→                  >
316→                    {expandedProjects.has(projectName) ? (
317→                      <ChevronDown className="w-3.5 h-3.5 shrink-0" />
318→                    ) : (
319→                      <ChevronRight className="w-3.5 h-3.5 shrink-0" />
320→                    )}
321→                    <FolderOpen className="w-3.5 h-3.5 shrink-0 text-zinc-500" />
322→                    <span className="truncate font-medium" title={projectName}>
323→                      {baseProjectName(projectName)}
324→                    </span>
325→                    <span className="ml-auto text-zinc-500 shrink-0">
326→                      {projectSessions.length}
327→                    </span>
328→                  </button>
329→                </div>
330→                {expandedProjects.has(projectName) &&
331→                  projectSessions.map((session) => (
332→                    <SessionRow
333→                      key={session.session_id}
334→                      session={session}
335→                      selectedId={selectedId}
336→                      checkedIds={checkedIds}
337→                      onSelect={onSelect}
338→                      onToggle={handleToggleOne}
339→                      showProject={false}
340→                    />
341→                  ))}
342→              </div>
343→              );
344→            })
345→        )}
346→      </div>
347→    </div>
348→  );
349→}
