366→  return (
367→    <div
368→      className={`flex items-center border-b border-zinc-800/50 transition-all duration-200 ${
369→        selectedId === session.session_id
370→          ? "bg-cyan-600/15 border-l-2 border-l-cyan-400"
371→          : "hover:bg-zinc-800/50 border-l-2 border-l-transparent"
372→      }`}
373→    >
374→      {/* Checkbox — indented under project header chevron when nested */}
375→      <button
376→        onClick={(e) => {
377→          e.stopPropagation();
378→          onToggle(session.session_id);
379→        }}
380→        className={`shrink-0 pr-1 text-zinc-500 hover:text-cyan-400 transition ${
381→          showProject ? "pl-3" : "pl-8"
382→        }`}
383→      >
384→        {checkedIds.has(session.session_id) ? (
385→          <CheckSquare className="w-3.5 h-3.5 text-cyan-400" />
386→        ) : (
387→          <Square className="w-3.5 h-3.5" />
388→        )}
389→      </button>
390→
391→      {/* Session content */}
392→      <button
393→        onClick={() => onSelect(session.session_id)}
394→        className="flex-1 text-left pr-3 py-2.5 min-w-0"
395→      >
396→        {showProject && (
397→          <div className="flex items-center justify-between mb-0.5">
398→            <span className="text-xs text-zinc-400 uppercase tracking-wide" title={session.project_path || ""}>
399→              {baseProjectName(session.project_path || "")}
400→            </span>
401→            <span className="text-xs text-zinc-400">
402→              {formatTime(session.timestamp ?? null)}
403→            </span>
404→          </div>
405→        )}
406→        <div className="flex items-center gap-2">
407→          <p className="text-sm text-zinc-200 line-clamp-2 leading-relaxed flex-1 min-w-0">
408→            {truncate(session.first_message || "", 120) || "Empty session"}
409→          </p>
410→          {!showProject && (
411→            <span className="text-xs text-zinc-400 shrink-0">
