 37→export function UploadDialog({ onClose, onComplete }: UploadDialogProps) {
 38→  const { fetchWithToken, sessionToken, maxZipBytes } = useAppContext();
 39→  const maxZipMB = Math.round(maxZipBytes / (1024 * 1024));
 40→  const [step, setStep] = useState<Step>("select");
