 70→
 71→  const fileTooLarge = file ? file.size > maxZipBytes : false;
 72→
 73→  const handleFileDrop = useCallback((e: React.DragEvent) => {
 74→    e.preventDefault();
 75→    setDragOver(false);
 76→    setResult(null);
 77→    const dropped = e.dataTransfer.files[0];
 78→    if (dropped && dropped.name.toLowerCase().endsWith(".zip")) {
 79→      setFile(dropped);
 80→    }
 81→  }, []);
 82→
 83→  const handleFileSelect = useCallback(
 84→    (e: React.ChangeEvent<HTMLInputElement>) => {
