104→    formData.append("agent_type", agentType);
105→
106→    const xhr = new XMLHttpRequest();
107→    xhr.open("POST", "/api/upload/zip");
108→    xhr.setRequestHeader("X-Session-Token", sessionToken);
109→
110→    xhr.upload.onprogress = (e) => {
111→      if (e.lengthComputable) {
112→        setUploadProgress(Math.round((e.loaded / e.total) * 100));
113→      }
114→    };
115→
116→    xhr.upload.onload = () => {
117→      setUploadPhase("processing");
118→    };
119→
120→    xhr.onload = () => {
121→      try {
122→        const data = JSON.parse(xhr.responseText);
123→        if (xhr.status >= 200 && xhr.status < 300) {
124→          setResult(data);
125→        } else {
126→          setResult({
127→            files_received: 1,
128→            sessions_parsed: 0,
129→            steps_stored: 0,
130→            skipped: 0,
131→            errors: [{ filename: file.name, error: data.detail || `HTTP ${xhr.status}` }],
132→          });
133→        }
134→      } catch {
135→        setResult({
136→          files_received: 1,
137→          sessions_parsed: 0,
138→          steps_stored: 0,
139→          skipped: 0,
140→          errors: [{ filename: file.name, error: xhr.responseText || `HTTP ${xhr.status}` }],
141→        });
142→      }
143→      setUploading(false);
144→    };
145→
146→    xhr.onerror = () => {
