149→        sessions_parsed: 0,
150→        steps_stored: 0,
151→        skipped: 0,
152→        errors: [{ filename: file.name, error: "Network error" }],
153→      });
154→      setUploading(false);
155→    };
156→
157→    xhr.send(formData);
158→  }, [file, agentType, sessionToken]);
159→
160→  const handleDone = useCallback(() => {
