206→
207→              {/* Agent selector */}
208→              <SelectorRow
209→                label="Agent"
210→                options={AGENT_OPTIONS.map((o) => ({
211→                  value: o.type,
212→                  label: o.label,
213→                }))}
214→                selected={agentType}
