400→        {options.map((opt) => (
401→          <button
402→            key={opt.value}
403→            onClick={() => onSelect(opt.value)}
404→            className={`px-3 py-1 text-xs rounded-full transition ${
405→              selected === opt.value
406→                ? "bg-violet-600 text-white"
407→                : "bg-zinc-800 text-zinc-400 border border-zinc-700 hover:border-zinc-500 hover:text-zinc-200"
408→            }`}
409→          >
410→            {opt.label}
411→          </button>
412→        ))}
413→      </div>
414→    </div>
415→  );
416→}
