 26→export function DashboardView({ cache }: DashboardViewProps) {
 27→  const { fetchWithToken } = useAppContext();
 28→  const [stats, setStats] = useState<DashboardStats | null>(cache?.stats ?? null);
 29→  const [toolUsage, setToolUsage] = useState<ToolUsageStat[]>(cache?.toolUsage ?? []);
 30→  const [loading, setLoading] = useState(!cache);
 31→  const [error, setError] = useState<string | null>(null);
