 33→  const [exporting, setExporting] = useState<"csv" | "json" | null>(null);
 34→  const [showAllProjects, setShowAllProjects] = useState(false);
 35→  const { tip, show, move, hide } = useTooltip();
 36→
 37→  // Populate from cache when it arrives (background preload)
 38→  useEffect(() => {
 39→    if (cache && !stats) {
 40→      setStats(cache.stats);
 41→      setToolUsage(cache.toolUsage);
 42→      setLoading(false);
 43→    }
 44→  }, [cache, stats]);
 45→
 46→  // Fetch on-demand only when filtering by project
 47→  useEffect(() => {
 48→    if (!selectedProject) return;
 49→
 50→    setLoading(true);
 51→    setError(null);
 52→    const params = new URLSearchParams();
 53→    params.set("project_path", selectedProject);
 54→
 55→    Promise.all([
 56→      fetchWithToken(`/api/analysis/dashboard?${params}`)
 57→        .then((r) => {
 58→          if (!r.ok) throw new Error(`HTTP ${r.status}`);
 59→          return r.json();
 60→        }),
 61→      fetchWithToken(`/api/analysis/tool-usage?${params}`)
 62→        .then((r) => (r.ok ? r.json() : []))
 63→        .catch(() => []),
 64→    ])
 65→      .then(([dashData, toolData]: [DashboardStats, ToolUsageStat[]]) => {
 66→        setStats(dashData);
 67→        setToolUsage(toolData);
 68→      })
 69→      .catch((err) => setError(String(err)))
 70→      .finally(() => setLoading(false));
 71→  }, [fetchWithToken, selectedProject]);
 72→
 73→  // Restore cached global data when clearing the project filter
 74→  const handleClearProject = useCallback(() => {
 75→    setSelectedProject(null);
 76→    if (cache) {
 77→      setStats(cache.stats);
 78→      setToolUsage(cache.toolUsage);
 79→    }
 80→  }, [cache]);
 81→
 82→  const handleExport = async (format: "csv" | "json") => {
 83→    setExporting(format);
 84→    const params = new URLSearchParams({ format });
